"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const button3DVariants = cva(
  [
    "relative inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium",
    "transition-all duration-150 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
    "disabled:pointer-events-none disabled:opacity-50 cursor-pointer select-none",
    "transform-gpu will-change-transform active:scale-95",
    "before:absolute before:inset-0 before:rounded-md before:transition-all before:duration-150",
    "after:absolute after:inset-0 after:rounded-md after:transition-all after:duration-150",
  ],
  {
    variants: {
      variant: {
        default: [
          "bg-primary text-primary-foreground shadow-md hover:bg-primary/90",
          "before:bg-gradient-to-t before:from-primary/80 before:to-primary before:translate-y-1 before:shadow-lg",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/20 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
        ],
        destructive: [
          "bg-destructive text-destructive-foreground shadow-md hover:bg-destructive/90",
          "before:bg-gradient-to-t before:from-destructive/80 before:to-destructive before:translate-y-1 before:shadow-lg",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/20 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
        ],
        outline: [
          "border border-input bg-background text-foreground shadow-sm hover:bg-accent hover:text-accent-foreground",
          "before:bg-gradient-to-t before:from-muted/50 before:to-background before:translate-y-1 before:border before:border-input",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/10 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
        ],
        secondary: [
          "bg-secondary text-secondary-foreground shadow-md hover:bg-secondary/80",
          "before:bg-gradient-to-t before:from-secondary/80 before:to-secondary before:translate-y-1 before:shadow-lg",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/20 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
        ],
        ghost: [
          "text-foreground hover:bg-accent hover:text-accent-foreground",
          "before:bg-gradient-to-t before:from-accent/30 before:to-accent/10 before:translate-y-1 before:opacity-0",
          "hover:before:opacity-100 hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/10 after:to-transparent after:opacity-0",
          "hover:after:opacity-50",
        ],
        link: [
          "text-primary underline-offset-4 hover:underline",
          "before:hidden after:hidden",
        ],
        neon: [
          "bg-gradient-to-r from-purple-500 to-pink-500 text-white shadow-lg",
          "before:bg-gradient-to-t before:from-purple-600 before:to-pink-600 before:translate-y-1 before:shadow-lg",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/30 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
          "hover:shadow-purple-500/25 hover:shadow-2xl",
        ],
        glass: [
          "bg-white/10 backdrop-blur-md border border-white/20 text-foreground shadow-lg",
          "before:bg-gradient-to-t before:from-white/5 before:to-white/20 before:translate-y-1 before:backdrop-blur-md before:border before:border-white/20",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/30 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
        ],
        gradient: [
          "bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500 text-white shadow-lg",
          "before:bg-gradient-to-t before:from-blue-600 before:via-purple-600 before:to-pink-600 before:translate-y-1 before:shadow-lg",
          "hover:before:translate-y-0.5 active:before:translate-y-0",
          "after:bg-gradient-to-b after:from-white/20 after:to-transparent after:opacity-0",
          "hover:after:opacity-100",
          "hover:bg-gradient-to-r hover:from-blue-400 hover:via-purple-400 hover:to-pink-400",
        ],
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        xl: "h-12 rounded-lg px-10 text-base",
        icon: "h-10 w-10",
      },
      depth: {
        none: "before:translate-y-0",
        sm: "before:translate-y-0.5 hover:before:translate-y-0 active:before:translate-y-0",
        default:
          "before:translate-y-1 hover:before:translate-y-0.5 active:before:translate-y-0",
        lg: "before:translate-y-1.5 hover:before:translate-y-0.5 active:before:translate-y-0",
        xl: "before:translate-y-2 hover:before:translate-y-1 active:before:translate-y-0",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
      depth: "default",
    },
  }
)

interface Button3DProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof button3DVariants> {
  asChild?: boolean
  tiltOnHover?: boolean
  glowIntensity?: number
  shadowColor?: string
  pressAnimation?: boolean
}

const Button3D = React.forwardRef<HTMLButtonElement, Button3DProps>(
  (
    {
      className,
      variant,
      size,
      depth,
      tiltOnHover = false,
      glowIntensity = 0,
      shadowColor,
      pressAnimation = true,
      children,
      onMouseEnter,
      onMouseLeave,
      onMouseMove,
      onMouseDown,
      onMouseUp,
      style,
      ...props
    },
    ref
  ) => {
    const buttonRef = React.useRef<HTMLButtonElement>(null)
    const [isHovered, setIsHovered] = React.useState(false)
    const [isPressed, setIsPressed] = React.useState(false)
    const [tiltTransform, setTiltTransform] = React.useState({ x: 0, y: 0 })

    const updateTilt = React.useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        if (!tiltOnHover || !buttonRef.current) return

        const rect = buttonRef.current.getBoundingClientRect()
        const centerX = rect.left + rect.width / 2
        const centerY = rect.top + rect.height / 2

        const deltaX = (e.clientX - centerX) / (rect.width / 2)
        const deltaY = (e.clientY - centerY) / (rect.height / 2)

        setTiltTransform({
          x: deltaY * -10, // Inverted for more natural feel
          y: deltaX * 10,
        })
      },
      [tiltOnHover]
    )

    const resetTilt = React.useCallback(() => {
      setTiltTransform({ x: 0, y: 0 })
    }, [])

    const handleMouseEnter = React.useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        setIsHovered(true)
        onMouseEnter?.(e)
      },
      [onMouseEnter]
    )

    const handleMouseLeave = React.useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        setIsHovered(false)
        resetTilt()
        onMouseLeave?.(e)
      },
      [onMouseLeave, resetTilt]
    )

    const handleMouseMove = React.useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        if (tiltOnHover) {
          updateTilt(e)
        }
        onMouseMove?.(e)
      },
      [onMouseMove, tiltOnHover, updateTilt]
    )

    const handleMouseDown = React.useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        if (pressAnimation) {
          setIsPressed(true)
        }
        onMouseDown?.(e)
      },
      [onMouseDown, pressAnimation]
    )

    const handleMouseUp = React.useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        setIsPressed(false)
        onMouseUp?.(e)
      },
      [onMouseUp]
    )

    React.useImperativeHandle(ref, () => buttonRef.current!)

    const buttonStyle: React.CSSProperties = {
      ...style,
      transform: tiltOnHover
        ? `perspective(1000px) rotateX(${tiltTransform.x}deg) rotateY(${tiltTransform.y}deg) ${isPressed ? "translateY(1px)" : ""}`
        : isPressed
          ? "translateY(1px)"
          : undefined,
      filter:
        glowIntensity > 0
          ? `drop-shadow(0 0 ${glowIntensity * 4}px ${shadowColor || "currentColor"})`
          : undefined,
      transition: "all 150ms cubic-bezier(0.4, 0, 0.2, 1)",
    }

    return (
      <button
        ref={buttonRef}
        className={cn(button3DVariants({ variant, size, depth }), className)}
        style={buttonStyle}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        onMouseMove={handleMouseMove}
        onMouseDown={handleMouseDown}
        onMouseUp={handleMouseUp}
        {...props}
      >
        <span className="relative z-10 flex items-center justify-center gap-2">
          {children}
        </span>
      </button>
    )
  }
)
Button3D.displayName = "Button3D"

// Preset button variants for common use cases
const Button3DPreset = {
  Hero: React.forwardRef<
    HTMLButtonElement,
    Omit<Button3DProps, "variant" | "size" | "depth">
  >((props, ref) => (
    <Button3D
      ref={ref}
      variant="gradient"
      size="xl"
      depth="lg"
      tiltOnHover
      glowIntensity={2}
      {...props}
    />
  )),

  CTA: React.forwardRef<
    HTMLButtonElement,
    Omit<Button3DProps, "variant" | "size" | "depth">
  >((props, ref) => (
    <Button3D
      ref={ref}
      variant="neon"
      size="lg"
      depth="default"
      tiltOnHover
      glowIntensity={1}
      {...props}
    />
  )),

  Glass: React.forwardRef<
    HTMLButtonElement,
    Omit<Button3DProps, "variant" | "size" | "depth">
  >((props, ref) => (
    <Button3D
      ref={ref}
      variant="glass"
      size="default"
      depth="sm"
      tiltOnHover
      {...props}
    />
  )),

  Minimal: React.forwardRef<
    HTMLButtonElement,
    Omit<Button3DProps, "variant" | "size" | "depth">
  >((props, ref) => (
    <Button3D ref={ref} variant="ghost" size="default" depth="sm" {...props} />
  )),

  Danger: React.forwardRef<
    HTMLButtonElement,
    Omit<Button3DProps, "variant" | "size" | "depth">
  >((props, ref) => (
    <Button3D
      ref={ref}
      variant="destructive"
      size="default"
      depth="default"
      shadowColor="rgb(239 68 68)"
      {...props}
    />
  )),
}

// Assign display names
Button3DPreset.Hero.displayName = "Button3DPreset.Hero"
Button3DPreset.CTA.displayName = "Button3DPreset.CTA"
Button3DPreset.Glass.displayName = "Button3DPreset.Glass"
Button3DPreset.Minimal.displayName = "Button3DPreset.Minimal"
Button3DPreset.Danger.displayName = "Button3DPreset.Danger"

// Loading button with 3D spinner
const Button3DLoading = React.forwardRef<
  HTMLButtonElement,
  Button3DProps & { loading?: boolean }
>(({ loading = false, children, disabled, ...props }, ref) => {
  return (
    <Button3D ref={ref} disabled={disabled || loading} {...props}>
      {loading && (
        <div className="animate-spin rounded-full h-4 w-4 border-2 border-current border-t-transparent" />
      )}
      {!loading && children}
    </Button3D>
  )
})
Button3DLoading.displayName = "Button3DLoading"

export {
  Button3D,
  Button3DPreset,
  Button3DLoading,
  button3DVariants,
  type Button3DProps,
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

interface Point {
  x: number
  y: number
}

interface Card3DProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode
  maxTilt?: number
  perspective?: number
  scale?: number
  speed?: number
  glare?: boolean
  glareMaxOpacity?: number
  className?: string
}

const Card3D = React.forwardRef<HTMLDivElement, Card3DProps>(
  (
    {
      children,
      maxTilt = 15,
      perspective = 1000,
      scale = 1.05,
      speed = 400,
      glare = true,
      glareMaxOpacity = 0.7,
      className,
      ...props
    },
    ref
  ) => {
    const cardRef = React.useRef<HTMLDivElement>(null)
    const glareRef = React.useRef<HTMLDivElement>(null)
    const [isHovered, setIsHovered] = React.useState(false)
    const [transforms, setTransforms] = React.useState({
      rotateX: 0,
      rotateY: 0,
      scale: 1,
      glareX: 50,
      glareY: 50,
      glareOpacity: 0,
    })

    const updateTransforms = React.useCallback(
      (point: Point | null, rect: DOMRect | null) => {
        if (!point || !rect) {
          setTransforms({
            rotateX: 0,
            rotateY: 0,
            scale: 1,
            glareX: 50,
            glareY: 50,
            glareOpacity: 0,
          })
          return
        }

        const centerX = rect.left + rect.width / 2
        const centerY = rect.top + rect.height / 2

        const deltaX = (point.x - centerX) / (rect.width / 2)
        const deltaY = (point.y - centerY) / (rect.height / 2)

        const rotateX = -deltaY * maxTilt
        const rotateY = deltaX * maxTilt

        const glareX = ((point.x - rect.left) / rect.width) * 100
        const glareY = ((point.y - rect.top) / rect.height) * 100

        setTransforms({
          rotateX,
          rotateY,
          scale,
          glareX,
          glareY,
          glareOpacity: glare ? glareMaxOpacity : 0,
        })
      },
      [maxTilt, scale, glare, glareMaxOpacity]
    )

    const handleMouseMove = React.useCallback(
      (e: React.MouseEvent) => {
        if (!cardRef.current) return

        const rect = cardRef.current.getBoundingClientRect()
        const point = { x: e.clientX, y: e.clientY }
        updateTransforms(point, rect)
      },
      [updateTransforms]
    )

    const handleTouchMove = React.useCallback(
      (e: React.TouchEvent) => {
        if (!cardRef.current || e.touches.length === 0) return

        e.preventDefault()
        const rect = cardRef.current.getBoundingClientRect()
        const touch = e.touches[0]
        const point = { x: touch.clientX, y: touch.clientY }
        updateTransforms(point, rect)
      },
      [updateTransforms]
    )

    const handleMouseEnter = React.useCallback(() => {
      setIsHovered(true)
    }, [])

    const handleMouseLeave = React.useCallback(() => {
      setIsHovered(false)
      updateTransforms(null, null)
    }, [updateTransforms])

    const handleTouchStart = React.useCallback(() => {
      setIsHovered(true)
    }, [])

    const handleTouchEnd = React.useCallback(() => {
      setIsHovered(false)
      updateTransforms(null, null)
    }, [updateTransforms])

    const cardStyle: React.CSSProperties = {
      transform: `perspective(${perspective}px) rotateX(${transforms.rotateX}deg) rotateY(${transforms.rotateY}deg) scale(${transforms.scale})`,
      transition: isHovered
        ? "none"
        : `transform ${speed}ms cubic-bezier(0.03, 0.98, 0.52, 0.99)`,
      transformStyle: "preserve-3d",
    }

    const glareStyle: React.CSSProperties = {
      background: `radial-gradient(circle at ${transforms.glareX}% ${transforms.glareY}%, rgba(255,255,255,${transforms.glareOpacity}) 0%, transparent 50%)`,
      transition: isHovered ? "none" : `opacity ${speed}ms ease-out`,
    }

    React.useImperativeHandle(ref, () => cardRef.current!)

    return (
      <div
        ref={cardRef}
        className={cn(
          "relative rounded-lg border bg-card text-card-foreground shadow-lg cursor-pointer",
          "transform-gpu will-change-transform",
          className
        )}
        style={cardStyle}
        onMouseMove={handleMouseMove}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        {...props}
      >
        {/* Content Layer */}
        <div className="relative z-10">{children}</div>

        {/* Glare Effect */}
        {glare && (
          <div
            ref={glareRef}
            className="absolute inset-0 rounded-lg pointer-events-none z-20"
            style={glareStyle}
          />
        )}
      </div>
    )
  }
)
Card3D.displayName = "Card3D"

// Depth layer components that work with 3D transforms
const Card3DHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & { depth?: number }
>(({ className, depth = 20, style, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex flex-col space-y-1.5 p-6", className)}
    style={{
      transform: `translateZ(${depth}px)`,
      ...style,
    }}
    {...props}
  />
))
Card3DHeader.displayName = "Card3DHeader"

const Card3DTitle = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLHeadingElement> & { depth?: number }
>(({ className, depth = 30, style, ...props }, ref) => (
  <h3
    ref={ref}
    className={cn(
      "text-2xl font-semibold leading-none tracking-tight",
      className
    )}
    style={{
      transform: `translateZ(${depth}px)`,
      ...style,
    }}
    {...props}
  />
))
Card3DTitle.displayName = "Card3DTitle"

const Card3DDescription = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLParagraphElement> & { depth?: number }
>(({ className, depth = 10, style, ...props }, ref) => (
  <p
    ref={ref}
    className={cn("text-sm text-muted-foreground", className)}
    style={{
      transform: `translateZ(${depth}px)`,
      ...style,
    }}
    {...props}
  />
))
Card3DDescription.displayName = "Card3DDescription"

const Card3DContent = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & { depth?: number }
>(({ className, depth = 25, style, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("p-6 pt-0", className)}
    style={{
      transform: `translateZ(${depth}px)`,
      ...style,
    }}
    {...props}
  />
))
Card3DContent.displayName = "Card3DContent"

const Card3DFooter = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & { depth?: number }
>(({ className, depth = 15, style, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex items-center p-6 pt-0", className)}
    style={{
      transform: `translateZ(${depth}px)`,
      ...style,
    }}
    {...props}
  />
))
Card3DFooter.displayName = "Card3DFooter"

export {
  Card3D,
  Card3DHeader,
  Card3DTitle,
  Card3DDescription,
  Card3DContent,
  Card3DFooter,
}

"use client"

import * as React from "react"
import { ChevronLeft, ChevronRight } from "lucide-react"

import { cn } from "@/lib/utils"

interface Carousel3DItem {
  id: string
  content: React.ReactNode
}

interface Carousel3DProps extends React.HTMLAttributes<HTMLDivElement> {
  items: Carousel3DItem[]
  itemWidth?: number
  itemHeight?: number
  spacing?: number
  perspective?: number
  rotateY?: number
  autoRotate?: boolean
  autoRotateSpeed?: number
  showControls?: boolean
  infinite?: boolean
  className?: string
}

const Carousel3D = React.forwardRef<HTMLDivElement, Carousel3DProps>(
  (
    {
      items,
      itemWidth = 300,
      itemHeight = 400,
      spacing = 80,
      perspective = 1000,
      rotateY = 40,
      autoRotate = false,
      autoRotateSpeed = 3000,
      showControls = true,
      infinite = true,
      className,
      ...props
    },
    ref
  ) => {
    const containerRef = React.useRef<HTMLDivElement>(null)
    const [currentIndex, setCurrentIndex] = React.useState(0)
    const [isHovered, setIsHovered] = React.useState(false)
    const [isDragging, setIsDragging] = React.useState(false)
    const [dragStart, setDragStart] = React.useState({ x: 0, y: 0 })
    const [dragOffset, setDragOffset] = React.useState(0)
    const autoRotateRef = React.useRef<NodeJS.Timeout | undefined>(undefined)

    const totalItems = items.length
    const radius = (itemWidth + spacing) / 2 / Math.tan(Math.PI / totalItems)

    // Auto rotation
    React.useEffect(() => {
      if (autoRotate && !isHovered && !isDragging) {
        autoRotateRef.current = setInterval(() => {
          setCurrentIndex((prev) => (prev + 1) % totalItems)
        }, autoRotateSpeed)
      } else {
        if (autoRotateRef.current) {
          clearInterval(autoRotateRef.current)
        }
      }

      return () => {
        if (autoRotateRef.current) {
          clearInterval(autoRotateRef.current)
        }
      }
    }, [autoRotate, isHovered, isDragging, autoRotateSpeed, totalItems])

    const goToPrevious = React.useCallback(() => {
      setCurrentIndex((prev) =>
        infinite ? (prev - 1 + totalItems) % totalItems : Math.max(0, prev - 1)
      )
    }, [infinite, totalItems])

    const goToNext = React.useCallback(() => {
      setCurrentIndex((prev) =>
        infinite ? (prev + 1) % totalItems : Math.min(totalItems - 1, prev + 1)
      )
    }, [infinite, totalItems])

    const goToIndex = React.useCallback(
      (index: number) => {
        setCurrentIndex(Math.max(0, Math.min(totalItems - 1, index)))
      },
      [totalItems]
    )

    // Touch and mouse drag handlers
    const handleDragStart = React.useCallback(
      (clientX: number, clientY: number) => {
        setIsDragging(true)
        setDragStart({ x: clientX, y: clientY })
        setDragOffset(0)
      },
      []
    )

    const handleDragMove = React.useCallback(
      (clientX: number, clientY: number) => {
        if (!isDragging) return

        const deltaX = clientX - dragStart.x
        const sensitivity = 0.5
        const newOffset = deltaX * sensitivity
        setDragOffset(newOffset)
      },
      [isDragging, dragStart.x]
    )

    const handleDragEnd = React.useCallback(() => {
      if (!isDragging) return

      const threshold = 50
      if (Math.abs(dragOffset) > threshold) {
        if (dragOffset > 0) {
          goToPrevious()
        } else {
          goToNext()
        }
      }

      setIsDragging(false)
      setDragOffset(0)
    }, [isDragging, dragOffset, goToPrevious, goToNext])

    // Mouse events
    const handleMouseDown = React.useCallback(
      (e: React.MouseEvent) => {
        e.preventDefault()
        handleDragStart(e.clientX, e.clientY)
      },
      [handleDragStart]
    )

    const handleMouseMove = React.useCallback(
      (e: React.MouseEvent) => {
        handleDragMove(e.clientX, e.clientY)
      },
      [handleDragMove]
    )

    const handleMouseUp = React.useCallback(() => {
      handleDragEnd()
    }, [handleDragEnd])

    // Touch events
    const handleTouchStart = React.useCallback(
      (e: React.TouchEvent) => {
        if (e.touches.length === 1) {
          const touch = e.touches[0]
          handleDragStart(touch.clientX, touch.clientY)
        }
      },
      [handleDragStart]
    )

    const handleTouchMove = React.useCallback(
      (e: React.TouchEvent) => {
        if (e.touches.length === 1) {
          e.preventDefault()
          const touch = e.touches[0]
          handleDragMove(touch.clientX, touch.clientY)
        }
      },
      [handleDragMove]
    )

    const handleTouchEnd = React.useCallback(() => {
      handleDragEnd()
    }, [handleDragEnd])

    // Keyboard navigation
    React.useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === "ArrowLeft") {
          e.preventDefault()
          goToPrevious()
        } else if (e.key === "ArrowRight") {
          e.preventDefault()
          goToNext()
        } else if (e.key >= "1" && e.key <= "9") {
          const index = parseInt(e.key) - 1
          if (index < totalItems) {
            goToIndex(index)
          }
        }
      }

      if (containerRef.current) {
        containerRef.current.addEventListener("keydown", handleKeyDown)
        return () => {
          containerRef.current?.removeEventListener("keydown", handleKeyDown)
        }
      }
    }, [goToPrevious, goToNext, goToIndex, totalItems])

    React.useImperativeHandle(ref, () => containerRef.current!)

    const containerStyle: React.CSSProperties = {
      perspective: `${perspective}px`,
      height: `${itemHeight + 100}px`,
    }

    const carouselStyle: React.CSSProperties = {
      transform: `translateZ(-${radius}px) rotateY(${-currentIndex * (360 / totalItems) + dragOffset / 5}deg)`,
      transition: isDragging
        ? "none"
        : "transform 0.6s cubic-bezier(0.4, 0.0, 0.2, 1)",
      transformStyle: "preserve-3d",
    }

    return (
      <div
        ref={containerRef}
        className={cn(
          "relative w-full select-none focus:outline-none",
          className
        )}
        style={containerStyle}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        tabIndex={0}
        {...props}
      >
        {/* 3D Carousel Container */}
        <div
          className="relative mx-auto"
          style={{
            width: `${itemWidth}px`,
            height: `${itemHeight}px`,
            transformStyle: "preserve-3d",
          }}
        >
          <div className="absolute inset-0" style={carouselStyle}>
            {items.map((item, index) => {
              const angle = (index / totalItems) * 360
              const isCurrent = index === currentIndex

              const itemStyle: React.CSSProperties = {
                transform: `rotateY(${angle}deg) translateZ(${radius}px)`,
                width: `${itemWidth}px`,
                height: `${itemHeight}px`,
                position: "absolute",
                backfaceVisibility: "hidden",
                transformStyle: "preserve-3d",
              }

              return (
                <div
                  key={item.id}
                  className={cn(
                    "rounded-lg border bg-card text-card-foreground shadow-lg cursor-pointer",
                    "transition-all duration-300 transform-gpu will-change-transform",
                    isCurrent && "ring-2 ring-primary ring-offset-2"
                  )}
                  style={itemStyle}
                  onClick={() => goToIndex(index)}
                >
                  <div className="w-full h-full overflow-hidden rounded-lg">
                    {item.content}
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        {/* Navigation Controls */}
        {showControls && (
          <>
            <button
              className={cn(
                "absolute left-4 top-1/2 -translate-y-1/2 z-10",
                "p-2 rounded-full bg-background/80 backdrop-blur-sm",
                "border shadow-lg hover:bg-background transition-all",
                "disabled:opacity-50 disabled:cursor-not-allowed"
              )}
              onClick={goToPrevious}
              disabled={!infinite && currentIndex === 0}
              aria-label="Previous item"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>

            <button
              className={cn(
                "absolute right-4 top-1/2 -translate-y-1/2 z-10",
                "p-2 rounded-full bg-background/80 backdrop-blur-sm",
                "border shadow-lg hover:bg-background transition-all",
                "disabled:opacity-50 disabled:cursor-not-allowed"
              )}
              onClick={goToNext}
              disabled={!infinite && currentIndex === totalItems - 1}
              aria-label="Next item"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </>
        )}

        {/* Indicators */}
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-10">
          <div className="flex space-x-2 p-2 rounded-full bg-background/80 backdrop-blur-sm border shadow-lg">
            {items.map((_, index) => (
              <button
                key={index}
                className={cn(
                  "w-2 h-2 rounded-full transition-all",
                  index === currentIndex
                    ? "bg-primary scale-125"
                    : "bg-muted-foreground/50 hover:bg-muted-foreground/75"
                )}
                onClick={() => goToIndex(index)}
                aria-label={`Go to item ${index + 1}`}
              />
            ))}
          </div>
        </div>

        {/* Auto-rotate indicator */}
        {autoRotate && (
          <div className="absolute top-4 right-4 z-10">
            <div className="flex items-center space-x-2 p-2 rounded-full bg-background/80 backdrop-blur-sm border shadow-sm">
              <div
                className={cn(
                  "w-2 h-2 rounded-full transition-all",
                  isHovered || isDragging
                    ? "bg-orange-500"
                    : "bg-green-500 animate-pulse"
                )}
              />
              <span className="text-xs text-muted-foreground">
                {isHovered || isDragging ? "Paused" : "Auto"}
              </span>
            </div>
          </div>
        )}
      </div>
    )
  }
)
