                size="icon"
              >
                <Send className="h-4 w-4" />
                <span className="sr-only">Send message</span>
              </Button>
            </div>
          </div>

          {/* Character count */}
          {maxLength && (
            <div className="mt-2 text-right text-xs text-muted-foreground">
              {input.length}/{maxLength}
            </div>
          )}
        </div>

        {/* Hidden file input */}
        {allowAttachments && (
          <input
            ref={fileInputRef}
            type="file"
            multiple
            accept={acceptedFileTypes.join(",")}
            className="hidden"
            onChange={handleFileSelect}
          />
        )}
      </div>
    )
  }
)
