    if (code.includes("any")) {
      suggestions.push({
        id: "debug-3",
        type: "debug",
        title: "Fix TypeScript Types",
        description: 'Using "any" type - consider using more specific types',
        severity: "error",
      })
    }

    return suggestions
  }

  const handleTest = async (code: string): Promise<string> => {
