                }}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {defaultVoices.map((voice) => (
                    <SelectItem key={voice.id} value={voice.id}>
                      {voice.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Speech Controls */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium">Speed</label>
                <Slider
                  value={[speechSpeed]}
                  onValueChange={([value]) => setSpeechSpeed(value)}
                  min={0.5}
                  max={2.0}
                  step={0.1}
                  className="w-full"
                />
                <div className="text-xs text-muted-foreground text-center">
                  {speechSpeed.toFixed(1)}x
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium">Pitch</label>
                <Slider
                  value={[speechPitch]}
                  onValueChange={([value]) => setSpeechPitch(value)}
                  min={0.5}
                  max={2.0}
                  step={0.1}
                  className="w-full"
                />
                <div className="text-xs text-muted-foreground text-center">
                  {speechPitch.toFixed(1)}x
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium">Volume</label>
                <Slider
                  value={[speechVolume]}
                  onValueChange={([value]) => setSpeechVolume(value)}
                  min={0.0}
                  max={1.0}
                  step={0.1}
                  className="w-full"
                />
                <div className="text-xs text-muted-foreground text-center">
                  {Math.round(speechVolume * 100)}%
                </div>
              </div>
            </div>

            {/* Keyboard Shortcuts */}
            <div className="space-y-2">
              <label className="text-sm font-medium">Keyboard Shortcuts</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-2 text-xs">
                <div className="flex justify-between">
                  <span>Toggle listening:</span>
                  <kbd className="bg-muted px-1 rounded">Space</kbd>
                </div>
                <div className="flex justify-between">
                  <span>Stop all:</span>
                  <kbd className="bg-muted px-1 rounded">Esc</kbd>
                </div>
                <div className="flex justify-between">
                  <span>Speak transcript:</span>
                  <kbd className="bg-muted px-1 rounded">Ctrl+Enter</kbd>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  )
}

