/**
 * Path morphing animation component
 */
function MorphingPath({
  paths,
  duration,
  strokeWidth = 2,
  autoAnimate,
  repeat,
  onComplete,
}: {
  paths: string[]
  duration: number
  strokeWidth: number
  autoAnimate: boolean
  repeat: boolean
  onComplete?: () => void
}) {
  const [currentPathIndex, setCurrentPathIndex] = useState(0)

  useEffect(() => {
    if (!autoAnimate || paths.length < 2) return

    const interval = setInterval(() => {
      setCurrentPathIndex((prev) => {
        const next = (prev + 1) % paths.length
        if (next === 0 && !repeat) {
          clearInterval(interval)
          onComplete?.()
        }
        return next
      })
    }, duration)

    return () => clearInterval(interval)
  }, [autoAnimate, paths.length, duration, repeat, onComplete])

  return (
    <motion.path
      d={paths[currentPathIndex]}
      fill="none"
      stroke="currentColor"
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      animate={{ d: paths[currentPathIndex] }}
      transition={{ duration: duration / 1000, ease: "easeInOut" }}
    />
  )
}

/**
 * Progressive drawing animation
 */
function DrawingPath({
  path,
  duration,
  strokeWidth = 2,
  progress,
  autoAnimate,
}: {
  path: string
  duration: number
  strokeWidth: number
  progress?: number
  autoAnimate: boolean
}) {
  const pathRef = useRef<SVGPathElement>(null)
  const [pathLength, setPathLength] = useState(0)

  useEffect(() => {
    if (pathRef.current) {
      const length = pathRef.current.getTotalLength()
      setPathLength(length)
    }
  }, [path])

  const animatedLength =
    progress !== undefined ? pathLength * progress : pathLength

  return (
    <motion.path
      ref={pathRef}
      d={path}
      fill="none"
      stroke="currentColor"
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      initial={{ pathLength: 0 }}
      animate={
        autoAnimate
          ? { pathLength: 1 }
          : { pathLength: animatedLength / pathLength }
      }
      transition={{ duration: duration / 1000, ease: "easeInOut" }}
      style={{
        strokeDasharray: pathLength,
        strokeDashoffset: pathLength - animatedLength,
      }}
    />
  )
}

