export interface AnimatedNumberProps {
  /**
   * Target value to animate to
   */
  value: number
  /**
   * Starting value for animation
   */
  from?: number
  /**
   * Animation duration in milliseconds
   */
  duration?: number
  /**
   * Number of decimal places
   */
  decimals?: number
  /**
   * Number format type
   */
  format?: "number" | "currency" | "percent"
  /**
   * Currency code for currency format
   */
  currency?: string
  /**
   * Locale for number formatting
   */
  locale?: string
  /**
   * Easing function
   */
  easing?: "linear" | "easeIn" | "easeOut" | "easeInOut" | "bounce" | "elastic"
  /**
   * Whether to start animation automatically
   */
  autoStart?: boolean
  /**
   * Callback when animation completes
   */
  onComplete?: (value: number) => void
  /**
   * Custom CSS class
   */
  className?: string
  /**
   * Custom styling
   */
  style?: React.CSSProperties
  /**
   * Prefix text
   */
  prefix?: string
  /**
   * Suffix text
   */
  suffix?: string
  /**
   * Whether to use spring animation
   */
  useSpring?: boolean
  /**
   * Spring configuration
   */
  springConfig?: {
    tension?: number
    friction?: number
    mass?: number
  }
  /**
   * Custom number separator
   */
  separator?: string
  /**
   * Whether to animate on hover
   */
  animateOnHover?: boolean
  /**
   * Hover animation value
   */
  hoverValue?: number
}

const easingFunctions = {
  linear: [0, 0, 1, 1],
  easeIn: [0.42, 0, 1, 1],
  easeOut: [0, 0, 0.58, 1],
  easeInOut: [0.42, 0, 0.58, 1],
  bounce: [0.68, -0.6, 0.32, 1.6],
  elastic: [0.175, 0.885, 0.32, 1.275],
} as const

/**
 * Custom hook for animated number with various formatting options
 */
function useAnimatedNumber(
  targetValue: number,
  from: number,
  duration: number,
  decimals: number,
  format: "number" | "currency" | "percent",
  currency: string,
  locale: string,
  easing: keyof typeof easingFunctions,
  autoStart: boolean,
  useSpringAnim: boolean,
  springConfig: { tension?: number; friction?: number; mass?: number },
  separator?: string
) {
  const [displayValue, setDisplayValue] = useState(from)
  const [isAnimating, setIsAnimating] = useState(false)
  const animationRef = useRef<number | null>(null)
  const prefersReducedMotion = usePrefersReducedMotion()

  // Spring animation
  const springValue = useSpring(from, {
    stiffness: springConfig.tension || 100,
    damping: springConfig.friction || 10,
    mass: springConfig.mass || 1,
  })

  // Motion value for non-spring animation
  const [motionValue, setMotionValue] = useState(from)

  const startAnimation = useCallback(() => {
    // Skip animation if reduced motion is preferred
    if (prefersReducedMotion) {
      setDisplayValue(targetValue)
      return
    }

    setIsAnimating(true)

    if (useSpringAnim) {
      springValue.set(targetValue)
    } else {
      // Custom easing animation
      const startTime = Date.now()
      const startValue = displayValue
      const distance = targetValue - startValue

      const animate = () => {
        const elapsed = Date.now() - startTime
        const progress = Math.min(elapsed / duration, 1)

        // Apply easing
        const easedProgress = progress // Will be enhanced with actual easing
        const currentValue = startValue + distance * easedProgress

        setDisplayValue(currentValue)
        setMotionValue(currentValue)

        if (progress < 1) {
          animationRef.current = requestAnimationFrame(animate)
        } else {
          setIsAnimating(false)
          animationRef.current = null
        }
      }

      animationRef.current = requestAnimationFrame(animate)
    }
  }, [
    targetValue,
    displayValue,
    duration,
    useSpringAnim,
    springValue,
    prefersReducedMotion,
  ])

  // Cleanup animation frame on unmount
  useEffect(() => {
    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current)
      }
    }
  }, [])

  // Listen to spring value changes
  useEffect(() => {
    if (useSpringAnim) {
      const unsubscribe = springValue.onChange((latest) => {
        setDisplayValue(latest)
        // For springs, consider animation complete when value stops changing significantly
        if (Math.abs(latest - targetValue) < 0.01) {
          setIsAnimating(false)
        }
      })

      return () => {
        unsubscribe()
      }
    }
  }, [springValue, useSpringAnim, targetValue])

  useEffect(() => {
    if (autoStart) {
      startAnimation()
    }
  }, [autoStart, startAnimation])

  const formattedValue = useMemo(() => {
    const roundedValue =
      Math.round(displayValue * Math.pow(10, decimals)) / Math.pow(10, decimals)

    try {
      switch (format) {
        case "currency":
          return new Intl.NumberFormat(locale, {
            style: "currency",
            currency: currency,
            minimumFractionDigits: decimals,
            maximumFractionDigits: decimals,
          }).format(roundedValue)

        case "percent":
          return new Intl.NumberFormat(locale, {
            style: "percent",
            minimumFractionDigits: decimals,
            maximumFractionDigits: decimals,
          }).format(roundedValue / 100)

        default:
          let formatted = new Intl.NumberFormat(locale, {
            minimumFractionDigits: decimals,
            maximumFractionDigits: decimals,
          }).format(roundedValue)

          if (separator && separator !== ",") {
            formatted = formatted.replace(/,/g, separator)
          }

          return formatted
      }
    } catch (error) {
      return roundedValue.toFixed(decimals)
    }
  }, [displayValue, decimals, format, currency, locale, separator])

  return {
    formattedValue,
    displayValue,
    isAnimating,
    startAnimation,
  }
}

/**
 * Animated number component with formatting and easing options
 */
export function AnimatedNumber({
  value,
  from = 0,
  duration = 2000,
  decimals = 0,
  format = "number",
  currency = "USD",
  locale = "en-US",
  easing = "easeOut",
  autoStart = true,
  onComplete,
  className,
  style,
  prefix = "",
  suffix = "",
  useSpring = false,
  springConfig = {},
  separator,
  animateOnHover = false,
  hoverValue,
}: AnimatedNumberProps) {
  const [isHovered, setIsHovered] = useState(false)
  const [animationKey, setAnimationKey] = useState(0)

  const currentValue =
    animateOnHover && isHovered && hoverValue !== undefined ? hoverValue : value

  const { formattedValue, displayValue, isAnimating, startAnimation } =
    useAnimatedNumber(
      currentValue,
      from,
      duration,
      decimals,
      format,
      currency,
      locale,
      easing,
      autoStart,
      useSpring,
      springConfig,
      separator
    )

  // Handle completion callback
  useEffect(() => {
    if (
      !isAnimating &&
      onComplete &&
      Math.abs(displayValue - currentValue) < 0.001
    ) {
      onComplete(displayValue)
    }
  }, [isAnimating, displayValue, currentValue, onComplete])

  // Handle hover animation
  useEffect(() => {
    if (animateOnHover && hoverValue !== undefined) {
      startAnimation()
    }
  }, [isHovered, animateOnHover, hoverValue, startAnimation])

  const handleMouseEnter = () => {
    if (animateOnHover) {
      setIsHovered(true)
    }
  }

  const handleMouseLeave = () => {
    if (animateOnHover) {
      setIsHovered(false)
    }
  }

  const prefersReducedMotion = usePrefersReducedMotion()

  return (
    <motion.span
      className={cn("inline-block tabular-nums", className)}
      style={style}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      initial={{ scale: 1 }}
      animate={
        !prefersReducedMotion && isAnimating
          ? { scale: [1, 1.05, 1] }
          : { scale: 1 }
      }
      transition={{ duration: 0.3 }}
    >
      {prefix}
      <motion.span
        key={animationKey}
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.3 }}
      >
        {formattedValue}
      </motion.span>
      {suffix}
    </motion.span>
  )
}

/**
 * Counter component with increment/decrement controls
 */
export interface AnimatedCounterProps
  extends Omit<AnimatedNumberProps, "value" | "from"> {
  /**
   * Initial value
   */
  initialValue?: number
  /**
   * Minimum value
   */
  min?: number
  /**
   * Maximum value
   */
  max?: number
  /**
   * Step increment
   */
  step?: number
  /**
   * Whether to show controls
   */
  showControls?: boolean
  /**
   * Custom increment button
   */
  incrementButton?: React.ReactNode
  /**
   * Custom decrement button
   */
  decrementButton?: React.ReactNode
  /**
   * Callback when value changes
   */
  onChange?: (value: number) => void
}

export function AnimatedCounter({
  initialValue = 0,
  min = -Infinity,
  max = Infinity,
  step = 1,
  showControls = true,
  incrementButton,
  decrementButton,
  onChange,
  className,
  ...props
}: AnimatedCounterProps) {
  const [currentValue, setCurrentValue] = useState(initialValue)

  const increment = () => {
    const newValue = Math.min(currentValue + step, max)
    setCurrentValue(newValue)
    onChange?.(newValue)
  }

  const decrement = () => {
    const newValue = Math.max(currentValue - step, min)
    setCurrentValue(newValue)
    onChange?.(newValue)
  }

  if (!showControls) {
    return (
      <AnimatedNumber value={currentValue} className={className} {...props} />
    )
  }

  return (
    <div className={cn("flex items-center gap-2", className)}>
      <motion.button
        onClick={decrement}
        disabled={currentValue <= min}
        className="flex h-8 w-8 items-center justify-center rounded border bg-background hover:bg-accent disabled:opacity-50"
        whileTap={{ scale: 0.95 }}
        whileHover={{ scale: 1.05 }}
      >
        {decrementButton || "−"}
      </motion.button>

      <AnimatedNumber value={currentValue} {...props} />

      <motion.button
        onClick={increment}
        disabled={currentValue >= max}
        className="flex h-8 w-8 items-center justify-center rounded border bg-background hover:bg-accent disabled:opacity-50"
        whileTap={{ scale: 0.95 }}
        whileHover={{ scale: 1.05 }}
      >
        {incrementButton || "+"}
      </motion.button>
    </div>
  )
}

export default AnimatedNumber

"use client"

import React, { useCallback, useEffect, useMemo, useState } from "react"
import { AnimatePresence, motion, Variants } from "motion/react"

import { cn } from "@/lib/utils"

/**
 * Custom hook to detect prefers-reduced-motion
 */
function usePrefersReducedMotion(): boolean {
  const [prefersReducedMotion, setPrefersReducedMotion] = useState(false)

  useEffect(() => {
    if (typeof window === "undefined") return

    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)")
    setPrefersReducedMotion(mediaQuery.matches)

    const handleChange = (event: MediaQueryListEvent) => {
      setPrefersReducedMotion(event.matches)
    }

    mediaQuery.addEventListener("change", handleChange)
    return () => mediaQuery.removeEventListener("change", handleChange)
  }, [])

  return prefersReducedMotion
}

export interface AnimatedTextProps {
  /**
   * Text to animate
   */
  text: string
  /**
   * Animation type
   */
  animation?:
    | "typewriter"
    | "wordReveal"
    | "letterShuffle"
    | "gradient"
    | "glitch"
  /**
   * Animation duration in milliseconds
   */
  duration?: number
  /**
   * Delay between characters/words in milliseconds
   */
  delay?: number
  /**
   * Whether to repeat the animation
   */
  repeat?: boolean
  /**
   * Repeat delay in milliseconds
   */
  repeatDelay?: number
  /**
   * Whether to start animation automatically
   */
  autoStart?: boolean
  /**
   * Callback when animation completes
   */
  onComplete?: () => void
  /**
   * Custom CSS class
   */
  className?: string
  /**
   * Custom styling
   */
  style?: React.CSSProperties
  /**
   * Gradient colors for gradient animation
   */
  gradientColors?: string[]
  /**
   * Glitch intensity (0-1)
   */
  glitchIntensity?: number
  /**
   * Cursor character for typewriter
   */
  cursor?: string
  /**
   * Whether to show cursor
   */
  showCursor?: boolean
}

const letterVariants: Variants = {
  hidden: { opacity: 0, y: 20 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: {
      delay: i * 0.05,
      duration: 0.3,
      ease: "easeOut",
    },
  }),
}

const wordVariants: Variants = {
  hidden: { opacity: 0, scale: 0.8, y: 20 },
  visible: (i: number) => ({
    opacity: 1,
    scale: 1,
    y: 0,
    transition: {
      delay: i * 0.1,
      duration: 0.5,
      ease: "easeOut",
    },
  }),
}

const glitchVariants: Variants = {
  glitch: {
    x: [0, -2, 2, -1, 1, 0],
    filter: [
      "hue-rotate(0deg)",
      "hue-rotate(90deg)",
      "hue-rotate(180deg)",
      "hue-rotate(270deg)",
      "hue-rotate(0deg)",
    ],
    transition: {
      duration: 0.2,
      repeat: Infinity,
      repeatType: "reverse",
    },
  },
}

/**
 * Generate random characters for shuffle effect
 */
function getRandomChar(): string {
  const chars =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*"
  return chars[Math.floor(Math.random() * chars.length)]
}

/**
 * Typewriter animation hook
 */
function useTypewriter(text: string, speed: number, autoStart: boolean) {
  const [displayText, setDisplayText] = useState("")
  const [isComplete, setIsComplete] = useState(false)
  const [currentIndex, setCurrentIndex] = useState(0)

  const startAnimation = useCallback(() => {
    setDisplayText("")
    setCurrentIndex(0)
    setIsComplete(false)
  }, [])

  useEffect(() => {
    if (!autoStart) return
    startAnimation()
  }, [text, autoStart, startAnimation])

  useEffect(() => {
    if (currentIndex < text.length && !isComplete) {
      const timer = setTimeout(() => {
        setDisplayText((prev) => prev + text[currentIndex])
        setCurrentIndex((prev) => prev + 1)
      }, speed)

      return () => clearTimeout(timer)
    } else if (currentIndex >= text.length) {
      setIsComplete(true)
    }
  }, [currentIndex, text, speed, isComplete])

  return { displayText, isComplete, startAnimation }
}

/**
 * Letter shuffle animation hook
 */
function useLetterShuffle(text: string, duration: number, autoStart: boolean) {
  const [displayText, setDisplayText] = useState(text)
  const [isAnimating, setIsAnimating] = useState(false)

  const startAnimation = useCallback(() => {
    setIsAnimating(true)
    let iterations = 0
    const maxIterations = text.length

    const interval = setInterval(() => {
      setDisplayText(() =>
        text
          .split("")
          .map((char, index) => {
            if (index < iterations) {
              return text[index]
            }
            return char === " " ? " " : getRandomChar()
          })
          .join("")
      )

      if (iterations >= maxIterations) {
        clearInterval(interval)
        setDisplayText(text)
        setIsAnimating(false)
      }

      iterations += 1 / 3
    }, duration / maxIterations)

    // Store interval ref for cleanup
    const currentInterval = interval
    return () => clearInterval(currentInterval)
  }, [text, duration])

  useEffect(() => {
    if (autoStart) {
      startAnimation()
    }
  }, [autoStart, startAnimation])

  return { displayText, isAnimating, startAnimation }
}

/**
 * Animated text component with multiple animation types
 */
export function AnimatedText({
  text,
  animation = "typewriter",
  duration = 2000,
  delay = 50,
  repeat = false,
  repeatDelay = 1000,
  autoStart = true,
  onComplete,
  className,
  style,
  gradientColors = ["#ff6b6b", "#4ecdc4", "#45b7d1", "#96ceb4", "#ffeaa7"],
  glitchIntensity = 0.5,
  cursor = "|",
  showCursor = true,
}: AnimatedTextProps) {
  const [animationKey, setAnimationKey] = useState(0)
  const [showGradient, setShowGradient] = useState(false)
  const prefersReducedMotion = usePrefersReducedMotion()

  // Disable animations if user prefers reduced motion
  const shouldAnimate = !prefersReducedMotion && autoStart

  const {
    displayText: typewriterText,
    isComplete: typewriterComplete,
    startAnimation: startTypewriter,
  } = useTypewriter(text, delay, shouldAnimate && animation === "typewriter")
  const {
    displayText: shuffleText,
    isAnimating: shuffleAnimating,
    startAnimation: startShuffle,
  } = useLetterShuffle(
    text,
    duration,
    shouldAnimate && animation === "letterShuffle"
  )

  // Handle repeat animation
  useEffect(() => {
    if (!repeat) return

    let timer: NodeJS.Timeout

    if (animation === "typewriter" && typewriterComplete) {
      timer = setTimeout(() => {
        startTypewriter()
      }, repeatDelay)
    } else if (animation === "letterShuffle" && !shuffleAnimating) {
      timer = setTimeout(() => {
        startShuffle()
      }, repeatDelay)
    } else if (["wordReveal", "gradient", "glitch"].includes(animation)) {
      timer = setTimeout(() => {
        setAnimationKey((prev) => prev + 1)
      }, duration + repeatDelay)
    }

    return () => clearTimeout(timer)
  }, [
    animation,
    typewriterComplete,
    shuffleAnimating,
    repeat,
    repeatDelay,
    duration,
    startTypewriter,
    startShuffle,
  ])

  // Handle completion callback
  useEffect(() => {
    if (!onComplete) return

    if (animation === "typewriter" && typewriterComplete) {
      onComplete()
    } else if (
      animation === "letterShuffle" &&
      !shuffleAnimating &&
      shuffleText === text
    ) {
      onComplete()
    }
  }, [
    animation,
    typewriterComplete,
    shuffleAnimating,
    onComplete,
    shuffleText,
    text,
  ])

  // Gradient animation effect
  useEffect(() => {
    if (animation === "gradient") {
      setShowGradient(true)
      const timer = setTimeout(() => setShowGradient(false), duration)
      return () => clearTimeout(timer)
    }
  }, [animation, duration, animationKey])

  const gradientStyle = useMemo(() => {
    if (animation !== "gradient" || !showGradient) return {}

    return {
      background: `linear-gradient(-45deg, ${gradientColors.join(", ")})`,
      backgroundSize: "400% 400%",
      WebkitBackgroundClip: "text",
      WebkitTextFillColor: "transparent",
      animation: `gradientShift ${duration}ms ease-in-out infinite`,
    }
  }, [animation, showGradient, gradientColors, duration])

  const renderContent = () => {
    // Show final text immediately if reduced motion is preferred
    if (prefersReducedMotion) {
      return <span>{text}</span>
    }

    switch (animation) {
      case "typewriter":
        return (
          <span className="relative">
            {typewriterText}
            {showCursor && (
              <motion.span
                animate={{ opacity: [0, 1, 0] }}
                transition={{ duration: 1, repeat: Infinity }}
                className="ml-1"
              >
                {cursor}
              </motion.span>
            )}
          </span>
        )

      case "wordReveal":
        return (
          <motion.div
            key={animationKey}
            className="flex flex-wrap gap-1"
            initial="hidden"
            animate="visible"
            onAnimationComplete={() => onComplete?.()}
          >
            {text.split(" ").map((word, i) => (
              <motion.span
                key={i}
                custom={i}
                variants={wordVariants}
                className="inline-block"
              >
                {word}
              </motion.span>
            ))}
          </motion.div>
        )

      case "letterShuffle":
        return <span>{shuffleText}</span>

      case "gradient":
        return (
          <motion.span
            key={animationKey}
            style={gradientStyle}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5 }}
            onAnimationComplete={() => onComplete?.()}
          >
            {text}
          </motion.span>
        )

      case "glitch":
        return (
          <motion.div
            key={animationKey}
            className="relative"
            onAnimationComplete={() => onComplete?.()}
          >
            <motion.span
              variants={glitchVariants}
              animate="glitch"
              style={{
                textShadow: `${glitchIntensity * 2}px 0 #ff0000, ${-glitchIntensity * 2}px 0 #00ffff`,
              }}
            >
              {text}
            </motion.span>
            <motion.span
              className="absolute inset-0 opacity-80"
              variants={glitchVariants}
              animate="glitch"
              style={{
                color: "#ff0000",
                left: `${glitchIntensity}px`,
                mixBlendMode: "multiply",
              }}
            >
              {text}
            </motion.span>
            <motion.span
              className="absolute inset-0 opacity-80"
              variants={glitchVariants}
              animate="glitch"
              style={{
                color: "#00ffff",
                left: `${-glitchIntensity}px`,
                mixBlendMode: "multiply",
              }}
            >
              {text}
            </motion.span>
          </motion.div>
        )

      default:
        return text
    }
  }

  return (
    <>
      {animation === "gradient" && (
        <style>{`
          @keyframes gradientShift {
            0%,
            100% {
              background-position: 0% 50%;
            }
            50% {
              background-position: 100% 50%;
            }
          }
        `}</style>
      )}
      <div className={cn("inline-block", className)} style={style}>
        <AnimatePresence mode="wait">{renderContent()}</AnimatePresence>
      </div>
    </>
  )
}

export default AnimatedText

