        setCopied(true)
        setTimeout(() => setCopied(false), 2000)
        toast.success("Code copied to clipboard")
      } catch (err) {
        console.error("Failed to copy:", err)
        toast.error("Failed to copy code")
      }
    }, [editorValue])

    const handleChange: OnChange = React.useCallback(
      (newValue, ev) => {
        setEditorValue(newValue || "")
        if (onChange) {
          onChange(newValue, ev)
        }
      },
      [onChange]
    )

    const resolveTheme = React.useMemo(() => {
      if (themeProp === "auto") {
        return systemTheme === "dark" ? "vs-dark" : "light"
      }
      return themeProp === "dark" ? "vs-dark" : "light"
    }, [themeProp, systemTheme])

    return (
      <div
        ref={ref}
        className={cn(
          "relative overflow-hidden rounded-md border bg-background",
          className
        )}
      >
        {(showLanguageSelector || showCopyButton) && (
          <div className="flex items-center justify-between border-b bg-muted/50 px-3 py-2">
            {showLanguageSelector && (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-8 gap-1 px-2 text-xs font-mono"
                  >
                    {languageDisplayNames[selectedLanguage] || selectedLanguage}
                    <ChevronDown className="h-3 w-3" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent
                  align="start"
                  className="max-h-80 overflow-auto"
                >
                  {availableLanguages.map((lang) => (
                    <DropdownMenuItem
                      key={lang}
                      onClick={() => setSelectedLanguage(lang)}
                      className="font-mono text-xs"
                    >
                      {languageDisplayNames[lang] || lang}
                    </DropdownMenuItem>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>
            )}
            {showCopyButton && (
              <Button
                variant="ghost"
                size="sm"
                className="h-8 gap-1.5 px-2 text-xs"
                onClick={handleCopy}
                disabled={!editorValue}
              >
                {copied ? (
                  <>
                    <Check className="h-3 w-3" />
                    Copied!
                  </>
                ) : (
                  <>
                    <Copy className="h-3 w-3" />
                    Copy
                  </>
                )}
              </Button>
            )}
          </div>
        )}
        <Editor
          height={height}
          defaultLanguage={language}
          language={selectedLanguage}
          value={editorValue}
          defaultValue={defaultValue}
          theme={resolveTheme}
          onChange={handleChange}
          onMount={onMount}
          options={{
            readOnly,
            lineNumbers: lineNumbers ? "on" : "off",
            minimap: {
              enabled: minimap,
            },
            wordWrap,
            fontSize,
            scrollBeyondLastLine: false,
            automaticLayout: true,
            tabSize: 2,
            insertSpaces: true,
            formatOnPaste: true,
            formatOnType: true,
            scrollbar: {
              vertical: "auto",
              horizontal: "auto",
              verticalScrollbarSize: 10,
              horizontalScrollbarSize: 10,
            },
            padding: {
              top: 16,
              bottom: 16,
            },
          }}
        />
      </div>
    )
  }
)

