import * as React from "react"
import { Check, Circle, Clock } from "lucide-react"

import { cn } from "@/lib/utils"

interface TimelineItem {
  id: string
  title: string
  description?: string
  date?: string
  time?: string
  status?: "completed" | "active" | "pending"
  icon?: React.ReactNode
  content?: React.ReactNode
}

interface TimelineProps extends React.HTMLAttributes<HTMLDivElement> {
  items: TimelineItem[]
  orientation?: "vertical" | "horizontal"
  variant?: "default" | "alternate" | "compact" | "simple"
  animated?: boolean
}

const Timeline = React.forwardRef<HTMLDivElement, TimelineProps>(
  (
    {
      className,
      items,
      orientation = "vertical",
      variant = "default",
      animated = true,
      ...props
    },
    ref
  ) => {
    const [visibleItems, setVisibleItems] = React.useState<Set<string>>(
      new Set()
    )

    React.useEffect(() => {
      if (!animated) {
        setVisibleItems(new Set(items.map((item) => item.id)))
        return
      }

      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              const id = entry.target.getAttribute("data-timeline-id")
              if (id) {
                setVisibleItems((prev) => new Set([...prev, id]))
              }
            }
          })
        },
        {
          threshold: 0.1,
          rootMargin: "50px",
        }
      )

      const elements = document.querySelectorAll("[data-timeline-id]")
      elements.forEach((el) => observer.observe(el))

      return () => observer.disconnect()
    }, [items, animated])

    const getStatusIcon = (status?: TimelineItem["status"]) => {
      switch (status) {
        case "completed":
          return <Check className="h-3 w-3" />
        case "active":
          return <Clock className="h-3 w-3 animate-pulse" />
        default:
          return null
      }
    }

    const getStatusColor = (status?: TimelineItem["status"]) => {
      switch (status) {
        case "completed":
          return "bg-green-500 text-white"
        case "active":
          return "bg-blue-500 text-white"
        case "pending":
          return "bg-gray-300 dark:bg-gray-600"
        default:
          return "bg-primary text-primary-foreground"
      }
    }

