"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import {
  Captions,
  Maximize,
  Minimize,
  Pause,
  PictureInPicture,
  Play,
  RotateCcw,
  Settings,
  SkipBack,
  SkipForward,
  Volume2,
  VolumeX,
} from "lucide-react"

import { cn } from "@/lib/utils"

import { Button } from "./button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "./dropdown-menu"
import { Slider } from "./slider"

// Types
export interface VideoSource {
  src: string
  type: string
  quality?: string
}

export interface SubtitleTrack {
  src: string
  label: string
  srcLang: string
  default?: boolean
}

export interface VideoPlayerProps
  extends Omit<
    React.HTMLAttributes<HTMLDivElement>,
    | "onPlay"
    | "onPause"
    | "onEnded"
    | "controls"
    | "onTimeUpdate"
    | "onVolumeChange"
  > {
  sources: VideoSource[]
  poster?: string
  subtitles?: SubtitleTrack[]
  autoPlay?: boolean
  loop?: boolean
  muted?: boolean
  preload?: "auto" | "metadata" | "none"
  controls?: boolean
  disableKeyboard?: boolean
  disablePictureInPicture?: boolean
  onPlay?: () => void
  onPause?: () => void
  onEnded?: () => void
  onTimeUpdate?: (currentTime: number, duration: number) => void
  onVolumeChange?: (volume: number) => void
  onQualityChange?: (quality: string) => void
  onSpeedChange?: (speed: number) => void
}

const videoPlayerVariants = cva(
  "relative bg-black rounded-lg overflow-hidden group",
  {
    variants: {
      size: {
        sm: "aspect-video max-w-md",
        md: "aspect-video max-w-2xl",
        lg: "aspect-video max-w-4xl",
        full: "w-full aspect-video",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
)

export interface VideoPlayerVariantProps
  extends VariantProps<typeof videoPlayerVariants> {}

const VideoPlayer = React.forwardRef<
  HTMLDivElement,
  VideoPlayerProps & VideoPlayerVariantProps
>(
  (
    {
      className,
      size,
      sources,
      poster,
      subtitles = [],
      autoPlay = false,
      loop = false,
      muted = false,
      preload = "metadata",
      controls = true,
      disableKeyboard = false,
      disablePictureInPicture = false,
      onPlay,
      onPause,
      onEnded,
      onTimeUpdate,
      onVolumeChange,
      onQualityChange,
      onSpeedChange,
      ...props
    },
    ref
  ) => {
    const videoRef = React.useRef<HTMLVideoElement>(null)
    const containerRef = React.useRef<HTMLDivElement>(null)
    const progressRef = React.useRef<HTMLDivElement>(null)
    const controlsTimeoutRef = React.useRef<NodeJS.Timeout | undefined>(
      undefined
    )

    // State
    const [isPlaying, setIsPlaying] = React.useState(false)
    const [currentTime, setCurrentTime] = React.useState(0)
    const [duration, setDuration] = React.useState(0)
    const [volume, setVolume] = React.useState(1)
    const [isMuted, setIsMuted] = React.useState(muted)
    const [isFullscreen, setIsFullscreen] = React.useState(false)
    const [showControls, setShowControls] = React.useState(true)
    const [playbackSpeed, setPlaybackSpeed] = React.useState(1)
    const [currentQuality, setCurrentQuality] = React.useState(
      sources.find((s) => s.quality)?.quality || "auto"
    )
    const [showSubtitles, setShowSubtitles] = React.useState(false)
    const [isBuffering, setIsBuffering] = React.useState(false)
    const [isPictureInPicture, setIsPictureInPicture] = React.useState(false)

    // Playback speeds
    const playbackSpeeds = [0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2]

    // Quality options
    const qualityOptions = React.useMemo(() => {
      const qualities = sources
        .filter((s) => s.quality)
        .map((s) => s.quality!)
        .filter((quality, index, arr) => arr.indexOf(quality) === index)
      return ["auto", ...qualities]
    }, [sources])

    // Format time helper
    const formatTime = (time: number) => {
      const hours = Math.floor(time / 3600)
      const minutes = Math.floor((time % 3600) / 60)
      const seconds = Math.floor(time % 60)

      if (hours > 0) {
        return `${hours}:${minutes.toString().padStart(2, "0")}:${seconds.toString().padStart(2, "0")}`
      }
      return `${minutes}:${seconds.toString().padStart(2, "0")}`
    }

    // Toggle play/pause
    const togglePlayPause = React.useCallback(() => {
      if (!videoRef.current) return

      if (isPlaying) {
        videoRef.current.pause()
      } else {
        videoRef.current.play()
      }
    }, [isPlaying])

    // Seek to time
    const seekTo = React.useCallback((time: number) => {
      if (!videoRef.current) return
      videoRef.current.currentTime = time
    }, [])

    // Skip forward/backward
    const skip = React.useCallback(
      (seconds: number) => {
        if (!videoRef.current) return
        const newTime = Math.max(0, Math.min(duration, currentTime + seconds))
        seekTo(newTime)
      },
      [currentTime, duration, seekTo]
    )

    // Toggle mute
    const toggleMute = React.useCallback(() => {
      if (!videoRef.current) return

      if (isMuted) {
        videoRef.current.volume = volume
        setIsMuted(false)
      } else {
        videoRef.current.volume = 0
        setIsMuted(true)
      }
    }, [isMuted, volume])

    // Change volume
    const changeVolume = React.useCallback(
      (newVolume: number) => {
        if (!videoRef.current) return

        const clampedVolume = Math.max(0, Math.min(1, newVolume))
        videoRef.current.volume = clampedVolume
        setVolume(clampedVolume)
        setIsMuted(clampedVolume === 0)
        onVolumeChange?.(clampedVolume)
      },
      [onVolumeChange]
    )

    // Toggle fullscreen
    const toggleFullscreen = React.useCallback(async () => {
      if (!containerRef.current) return

      try {
        if (!document.fullscreenElement) {
          await containerRef.current.requestFullscreen()
          setIsFullscreen(true)
        } else {
          await document.exitFullscreen()
          setIsFullscreen(false)
        }
      } catch (error) {
        console.error("Fullscreen error:", error)
      }
    }, [])

    // Toggle picture-in-picture
    const togglePictureInPicture = React.useCallback(async () => {
      if (!videoRef.current || disablePictureInPicture) return

      try {
        if (document.pictureInPictureElement) {
          await document.exitPictureInPicture()
        } else {
          await videoRef.current.requestPictureInPicture()
        }
      } catch (error) {
        console.error("Picture-in-picture error:", error)
      }
    }, [disablePictureInPicture])

    // Change playback speed
    const changePlaybackSpeed = React.useCallback(
      (speed: number) => {
        if (!videoRef.current) return

        videoRef.current.playbackRate = speed
        setPlaybackSpeed(speed)
        onSpeedChange?.(speed)
      },
      [onSpeedChange]
    )

    // Change quality
    const changeQuality = React.useCallback(
      (quality: string) => {
        if (!videoRef.current) return

        const currentTimeBeforeChange = videoRef.current.currentTime
        const wasPlaying = !videoRef.current.paused

        if (quality === "auto") {
          // Use first source for auto
          videoRef.current.src = sources[0].src
        } else {
          const qualitySource = sources.find((s) => s.quality === quality)
          if (qualitySource) {
            videoRef.current.src = qualitySource.src
          }
        }

        videoRef.current.addEventListener(
          "loadedmetadata",
          () => {
            videoRef.current!.currentTime = currentTimeBeforeChange
            if (wasPlaying) {
              videoRef.current!.play()
            }
          },
          { once: true }
        )

        setCurrentQuality(quality)
        onQualityChange?.(quality)
      },
      [sources, onQualityChange]
    )

    // Hide controls after timeout
    const hideControlsAfterTimeout = React.useCallback(() => {
      if (controlsTimeoutRef.current) {
        clearTimeout(controlsTimeoutRef.current)
      }

      controlsTimeoutRef.current = setTimeout(() => {
        if (isPlaying) {
          setShowControls(false)
        }
      }, 3000)
    }, [isPlaying])

    // Show controls
    const showControlsTemporarily = React.useCallback(() => {
      setShowControls(true)
      hideControlsAfterTimeout()
    }, [hideControlsAfterTimeout])

    // Keyboard shortcuts
    React.useEffect(() => {
      if (disableKeyboard) return

      const handleKeyDown = (e: KeyboardEvent) => {
        if (!containerRef.current?.contains(document.activeElement)) return

        switch (e.code) {
          case "Space":
            e.preventDefault()
            togglePlayPause()
            break
          case "KeyF":
            e.preventDefault()
            toggleFullscreen()
            break
          case "KeyM":
            e.preventDefault()
            toggleMute()
            break
          case "ArrowLeft":
            e.preventDefault()
            skip(-10)
            break
          case "ArrowRight":
            e.preventDefault()
            skip(10)
            break
          case "ArrowUp":
            e.preventDefault()
            changeVolume(volume + 0.1)
            break
          case "ArrowDown":
            e.preventDefault()
            changeVolume(volume - 0.1)
            break
          case "KeyC":
            e.preventDefault()
            setShowSubtitles(!showSubtitles)
            break
          case "KeyP":
            e.preventDefault()
            togglePictureInPicture()
            break
        }

        showControlsTemporarily()
      }

      document.addEventListener("keydown", handleKeyDown)
      return () => document.removeEventListener("keydown", handleKeyDown)
    }, [
      disableKeyboard,
      togglePlayPause,
      toggleFullscreen,
      toggleMute,
      skip,
      changeVolume,
      volume,
      showSubtitles,
      togglePictureInPicture,
      showControlsTemporarily,
    ])

    // Video event handlers
    React.useEffect(() => {
      const video = videoRef.current
      if (!video) return

      const handlePlay = () => {
        setIsPlaying(true)
        setIsBuffering(false)
        onPlay?.()
        hideControlsAfterTimeout()
      }

      const handlePause = () => {
        setIsPlaying(false)
        setIsBuffering(false)
        onPause?.()
        setShowControls(true)
      }

      const handleTimeUpdate = () => {
        const currentTime = video.currentTime
        const duration = video.duration
        setCurrentTime(currentTime)
        setDuration(duration)
        onTimeUpdate?.(currentTime, duration)
      }

      const handleLoadedMetadata = () => {
        setDuration(video.duration)
        setIsBuffering(false)
      }

      const handleWaiting = () => {
        setIsBuffering(true)
      }

      const handleCanPlay = () => {
        setIsBuffering(false)
      }

      const handleEnded = () => {
        setIsPlaying(false)
        setShowControls(true)
        onEnded?.()
      }

      const handleVolumeChange = () => {
        setVolume(video.volume)
        setIsMuted(video.muted)
      }

      const handleEnterpictureinpicture = () => {
        setIsPictureInPicture(true)
      }

      const handleLeavepictureinpicture = () => {
        setIsPictureInPicture(false)
      }

      video.addEventListener("play", handlePlay)
      video.addEventListener("pause", handlePause)
      video.addEventListener("timeupdate", handleTimeUpdate)
      video.addEventListener("loadedmetadata", handleLoadedMetadata)
      video.addEventListener("waiting", handleWaiting)
      video.addEventListener("canplay", handleCanPlay)
      video.addEventListener("ended", handleEnded)
      video.addEventListener("volumechange", handleVolumeChange)
      video.addEventListener(
        "enterpictureinpicture",
        handleEnterpictureinpicture
      )
      video.addEventListener(
        "leavepictureinpicture",
        handleLeavepictureinpicture
      )

      return () => {
        video.removeEventListener("play", handlePlay)
        video.removeEventListener("pause", handlePause)
        video.removeEventListener("timeupdate", handleTimeUpdate)
        video.removeEventListener("loadedmetadata", handleLoadedMetadata)
        video.removeEventListener("waiting", handleWaiting)
        video.removeEventListener("canplay", handleCanPlay)
        video.removeEventListener("ended", handleEnded)
        video.removeEventListener("volumechange", handleVolumeChange)
        video.removeEventListener(
          "enterpictureinpicture",
          handleEnterpictureinpicture
        )
        video.removeEventListener(
          "leavepictureinpicture",
          handleLeavepictureinpicture
        )
      }
    }, [onPlay, onPause, onTimeUpdate, onEnded, hideControlsAfterTimeout])

    // Fullscreen change handler
    React.useEffect(() => {
      const handleFullscreenChange = () => {
        setIsFullscreen(!!document.fullscreenElement)
      }

      document.addEventListener("fullscreenchange", handleFullscreenChange)
      return () =>
        document.removeEventListener("fullscreenchange", handleFullscreenChange)
    }, [])

    // Mouse movement handler for controls
    React.useEffect(() => {
      const container = containerRef.current
      if (!container) return

      const handleMouseMove = () => {
        showControlsTemporarily()
      }

      const handleMouseLeave = () => {
        if (isPlaying && controlsTimeoutRef.current) {
          clearTimeout(controlsTimeoutRef.current)
          controlsTimeoutRef.current = setTimeout(() => {
            setShowControls(false)
          }, 1000)
        }
      }

      container.addEventListener("mousemove", handleMouseMove)
      container.addEventListener("mouseleave", handleMouseLeave)

      return () => {
        container.removeEventListener("mousemove", handleMouseMove)
        container.removeEventListener("mouseleave", handleMouseLeave)
      }
    }, [isPlaying, showControlsTemporarily])

    return (
      <div
        ref={containerRef}
        className={cn(videoPlayerVariants({ size, className }))}
        tabIndex={0}
        {...props}
      >
        <video
          ref={videoRef}
          className="w-full h-full object-contain"
          poster={poster}
          autoPlay={autoPlay}
          loop={loop}
          muted={muted}
          preload={preload}
          playsInline
          onClick={togglePlayPause}
        >
          {sources.map((source, index) => (
            <source key={index} src={source.src} type={source.type} />
          ))}
          {subtitles.map((track, index) => (
            <track
              key={index}
              kind="subtitles"
              src={track.src}
              srcLang={track.srcLang}
              label={track.label}
              default={track.default || index === 0}
            />
          ))}
          Your browser does not support the video tag.
        </video>

        {/* Loading indicator */}
        {isBuffering && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/50">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-white"></div>
          </div>
        )}

        {/* Controls */}
        {controls && (
          <div
            className={cn(
              "absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent transition-opacity duration-300",
              showControls ? "opacity-100" : "opacity-0"
            )}
          >
            {/* Progress bar */}
            <div className="absolute bottom-16 left-4 right-4">
              <div
                ref={progressRef}
                className="h-1 bg-white/30 rounded-full cursor-pointer group/progress"
                onClick={(e) => {
                  if (!progressRef.current) return
                  const rect = progressRef.current.getBoundingClientRect()
                  const percentage = (e.clientX - rect.left) / rect.width
                  seekTo(percentage * duration)
                }}
              >
                <div
                  className="h-full bg-primary rounded-full relative group-hover/progress:h-1.5 transition-all"
                  style={{ width: `${(currentTime / duration) * 100}%` }}
                >
                  <div className="absolute -top-1 -right-1 w-3 h-3 bg-primary rounded-full opacity-0 group-hover/progress:opacity-100 transition-opacity" />
                </div>
              </div>
            </div>

            {/* Control buttons */}
            <div className="absolute bottom-4 left-4 right-4 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/20"
                  onClick={() => skip(-10)}
                >
                  <RotateCcw className="h-4 w-4" />
                </Button>

                <Button
                  variant="ghost"
                  size="icon"
                  className="h-10 w-10 text-white hover:bg-white/20"
                  onClick={togglePlayPause}
                >
                  {isPlaying ? (
                    <Pause className="h-5 w-5" />
                  ) : (
                    <Play className="h-5 w-5" />
                  )}
                </Button>

                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/20"
                  onClick={() => skip(10)}
                >
                  <SkipForward className="h-4 w-4" />
                </Button>

                <div className="flex items-center gap-2 ml-4">
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8 text-white hover:bg-white/20"
                    onClick={toggleMute}
                  >
                    {isMuted || volume === 0 ? (
                      <VolumeX className="h-4 w-4" />
                    ) : (
                      <Volume2 className="h-4 w-4" />
                    )}
                  </Button>

                  <div className="w-20">
                    <Slider
                      value={[isMuted ? 0 : volume]}
                      max={1}
                      step={0.1}
                      onValueChange={([value]) => changeVolume(value)}
                      className="w-full"
                    />
                  </div>
                </div>

                <div className="text-white text-sm ml-4">
                  {formatTime(currentTime)} / {formatTime(duration)}
                </div>
              </div>

              <div className="flex items-center gap-2">
                {subtitles.length > 0 && (
                  <Button
                    variant="ghost"
                    size="icon"
                    className={cn(
                      "h-8 w-8 text-white hover:bg-white/20",
                      showSubtitles && "bg-white/20"
                    )}
                    onClick={() => setShowSubtitles(!showSubtitles)}
                  >
                    <Captions className="h-4 w-4" />
                  </Button>
                )}

                {/* Speed selector */}
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="h-8 px-2 text-white hover:bg-white/20"
                    >
                      {playbackSpeed}x
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent>
                    {playbackSpeeds.map((speed) => (
                      <DropdownMenuItem
                        key={speed}
                        onClick={() => changePlaybackSpeed(speed)}
                        className={cn(playbackSpeed === speed && "bg-accent")}
                      >
                        {speed}x
                      </DropdownMenuItem>
                    ))}
                  </DropdownMenuContent>
                </DropdownMenu>

                {/* Quality selector */}
                {qualityOptions.length > 1 && (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 text-white hover:bg-white/20"
                      >
                        <Settings className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent>
                      {qualityOptions.map((quality) => (
                        <DropdownMenuItem
                          key={quality}
                          onClick={() => changeQuality(quality)}
                          className={cn(
                            currentQuality === quality && "bg-accent"
                          )}
                        >
                          {quality}
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                )}

                {!disablePictureInPicture && (
                  <Button
                    variant="ghost"
                    size="icon"
                    className={cn(
                      "h-8 w-8 text-white hover:bg-white/20",
                      isPictureInPicture && "bg-white/20"
                    )}
                    onClick={togglePictureInPicture}
                  >
                    <PictureInPicture className="h-4 w-4" />
                  </Button>
                )}

                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/20"
                  onClick={toggleFullscreen}
                >
                  {isFullscreen ? (
                    <Minimize className="h-4 w-4" />
                  ) : (
                    <Maximize className="h-4 w-4" />
                  )}
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    )
  }
)

VideoPlayer.displayName = "VideoPlayer"

export { VideoPlayer, videoPlayerVariants }

"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import {
  Maximize,
  Maximize2,
  Minimize2,
  Play,
  Volume2,
  VolumeX,
  X,
} from "lucide-react"

import { cn } from "@/lib/utils"

// Types
export interface YouTubePipPlayerProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onPlay" | "onPause"> {
  /** YouTube video ID or array of IDs for rotation */
  videoId: string | string[]
  /** Auto-rotate videos every N seconds (default: 30) */
  rotationInterval?: number
  /** Enable scroll-based PIP mode */
  enablePip?: boolean
  /** Initial muted state (default: true) */
  defaultMuted?: boolean
  /** Show live indicator */
  showLiveIndicator?: boolean
  /** Enable TV-style visual effects */
  enableTvEffects?: boolean
  /** PIP position (default: bottom-right) */
  pipPosition?: "bottom-right" | "bottom-left" | "top-right" | "top-left"
  /** Callbacks */
  onPlay?: () => void
  onPause?: () => void
  onPipEnter?: () => void
  onPipExit?: () => void
  onMuteChange?: (muted: boolean) => void
}

const pipPositionStyles = {
  "bottom-right": {
    defaultX: (w: number, pipW: number) => w - pipW - 24,
    defaultY: (h: number, pipH: number) => h - pipH - 24,
  },
  "bottom-left": {
    defaultX: () => 24,
    defaultY: (h: number, pipH: number) => h - pipH - 24,
  },
  "top-right": {
    defaultX: (w: number, pipW: number) => w - pipW - 24,
    defaultY: () => 24,
  },
  "top-left": { defaultX: () => 24, defaultY: () => 24 },
}

const youtubePipPlayerVariants = cva(
  "relative bg-black rounded-[30px] overflow-hidden",
  {
    variants: {
      size: {
        sm: "aspect-video max-w-md",
        md: "aspect-video max-w-2xl",
        lg: "aspect-video max-w-4xl",
        full: "w-full aspect-video",
        hero: "w-full max-h-[calc(100vh-160px)]",
      },
    },
    defaultVariants: {
      size: "hero",
    },
  }
)

export interface YouTubePipPlayerVariantProps
  extends VariantProps<typeof youtubePipPlayerVariants> {}

const YouTubePipPlayer = React.forwardRef<
  HTMLDivElement,
  YouTubePipPlayerProps & YouTubePipPlayerVariantProps
>(
  (
    {
      className,
      size,
      videoId,
      rotationInterval = 30000,
      enablePip = true,
      defaultMuted = true,
      showLiveIndicator = true,
      enableTvEffects = true,
      pipPosition = "bottom-right",
      onPlay,
      onPause,
      onPipEnter,
      onPipExit,
      onMuteChange,
      ...props
    },
    ref
  ) => {
    // Normalize videoIds to array
    const videoIds = React.useMemo(
      () => (Array.isArray(videoId) ? videoId : [videoId]),
      [videoId]
    )

    // State
    const [currentVideoIndex, setCurrentVideoIndex] = React.useState(0)
    const [isMuted, setIsMuted] = React.useState(defaultMuted)
    const [isPip, setIsPip] = React.useState(false)
    const [showPip, setShowPip] = React.useState(true)
    const [pipSize, setPipSize] = React.useState<
      "normal" | "double" | "fullscreen"
    >("normal")
    const [isMobile, setIsMobile] = React.useState(false)
    const [isHovered, setIsHovered] = React.useState(false)
    const [isPipHovered, setIsPipHovered] = React.useState(false)
    const [showStatic, setShowStatic] = React.useState(false)

    // Dragging state
    const [pipPos, setPipPos] = React.useState({ x: 0, y: 0 })
    const [isDragging, setIsDragging] = React.useState(false)
    const [dragStart, setDragStart] = React.useState({ x: 0, y: 0 })
    const [hasDragged, setHasDragged] = React.useState(false)

    // Refs
    const containerRef = React.useRef<HTMLDivElement>(null)
    const pipContainerRef = React.useRef<HTMLDivElement>(null)

    // Constants
    const PIP_WIDTH_BASE = 384
    const PIP_MARGIN = 24

    // Calculate current PIP width
    const getCurrentPipWidth = React.useCallback(() => {
      return pipSize === "double" ? PIP_WIDTH_BASE * 2 : PIP_WIDTH_BASE
    }, [pipSize])

    // Get YouTube embed URL
    const getYouTubeEmbedUrl = React.useCallback(
      (forPip = false) => {
        const currentId = videoIds[currentVideoIndex]
        const muteParam =
          forPip && isPip ? (isMuted ? "1" : "0") : isMuted ? "1" : "0"
        return `https://www.youtube.com/embed/${currentId}?autoplay=1&mute=${muteParam}&controls=0&showinfo=0&rel=0&modestbranding=1&playsinline=1`
      },
      [videoIds, currentVideoIndex, isMuted, isPip]
    )

    // Mobile detection
    React.useEffect(() => {
      const checkMobile = () => setIsMobile(window.innerWidth < 768)
      checkMobile()
      window.addEventListener("resize", checkMobile)
      return () => window.removeEventListener("resize", checkMobile)
    }, [])

    // Video rotation
    React.useEffect(() => {
      if (videoIds.length <= 1) return
      const interval = setInterval(() => {
        setCurrentVideoIndex((prev) => (prev + 1) % videoIds.length)
      }, rotationInterval)
      return () => clearInterval(interval)
    }, [videoIds.length, rotationInterval])

    // TV static effect
    React.useEffect(() => {
      if (!enableTvEffects) return
      const interval = setInterval(() => {
        setShowStatic(true)
        setTimeout(() => setShowStatic(false), 200)
      }, 30000)
      return () => clearInterval(interval)
    }, [enableTvEffects])

    // Scroll-based PIP activation
    React.useEffect(() => {
      if (!enablePip) return

      const handleScroll = () => {
        if (!containerRef.current) return
        const rect = containerRef.current.getBoundingClientRect()
        const shouldShowPip = rect.bottom < 100
        const wasInPip = isPip

        setIsPip(shouldShowPip)

        if (shouldShowPip !== wasInPip) {
          if (shouldShowPip) {
            onPipEnter?.()
          } else {
            onPipExit?.()
          }
        }
      }

      window.addEventListener("scroll", handleScroll)
      return () => window.removeEventListener("scroll", handleScroll)
    }, [enablePip, isPip, onPipEnter, onPipExit])

    // Initialize PIP position
    React.useEffect(() => {
      if (typeof window === "undefined") return
      const pipWidth = getCurrentPipWidth()
      const pipHeight = (pipWidth * 9) / 16
      const pos = pipPositionStyles[pipPosition]
      setPipPos({
        x: pos.defaultX(window.innerWidth, pipWidth),
        y: pos.defaultY(window.innerHeight, pipHeight),
      })
    }, [getCurrentPipWidth, pipPosition])

    // Update position when size changes
    React.useEffect(() => {
      if (pipSize === "fullscreen" || typeof window === "undefined") return
      const pipWidth = getCurrentPipWidth()
      const pipHeight = (pipWidth * 9) / 16
      const pos = pipPositionStyles[pipPosition]
      setPipPos({
        x: pos.defaultX(window.innerWidth, pipWidth),
        y: pos.defaultY(window.innerHeight, pipHeight),
      })
    }, [pipSize, getCurrentPipWidth, pipPosition])

    // Dragging handlers
    const handleMouseDown = React.useCallback(
      (e: React.MouseEvent) => {
        if (pipSize === "fullscreen") return
        setIsDragging(true)
        setHasDragged(false)
        setDragStart({
          x: e.clientX - pipPos.x,
          y: e.clientY - pipPos.y,
        })
      },
      [pipSize, pipPos]
    )

    const handleMouseMove = React.useCallback(
      (e: MouseEvent) => {
        if (!isDragging || pipSize === "fullscreen") return

        const newX = e.clientX - dragStart.x
        const newY = e.clientY - dragStart.y

        const distanceMoved = Math.sqrt(
          Math.pow(newX - pipPos.x, 2) + Math.pow(newY - pipPos.y, 2)
        )
        if (distanceMoved > 5) setHasDragged(true)

        const pipWidth = getCurrentPipWidth()
        const maxX = window.innerWidth - pipWidth - PIP_MARGIN
        const maxY = window.innerHeight - (pipWidth * 9) / 16 - PIP_MARGIN

        setPipPos({
          x: Math.max(PIP_MARGIN, Math.min(newX, maxX)),
          y: Math.max(PIP_MARGIN, Math.min(newY, maxY)),
        })
      },
      [isDragging, pipSize, dragStart, pipPos, getCurrentPipWidth]
    )

    const handleMouseUp = React.useCallback(() => {
      if (isDragging && hasDragged) {
        // Snap to corner
        const pipWidth = getCurrentPipWidth()
        const pipHeight = (pipWidth * 9) / 16
        const pos = pipPositionStyles[pipPosition]
        setPipPos({
          x: pos.defaultX(window.innerWidth, pipWidth),
          y: pos.defaultY(window.innerHeight, pipHeight),
        })
      }
      setIsDragging(false)
      setHasDragged(false)
    }, [isDragging, hasDragged, getCurrentPipWidth, pipPosition])

    // Mouse event listeners for dragging
    React.useEffect(() => {
      if (!isDragging) return
      window.addEventListener("mousemove", handleMouseMove)
      window.addEventListener("mouseup", handleMouseUp)
      return () => {
        window.removeEventListener("mousemove", handleMouseMove)
        window.removeEventListener("mouseup", handleMouseUp)
      }
    }, [isDragging, handleMouseMove, handleMouseUp])

    // Toggle mute
    const toggleMute = React.useCallback(
      (e: React.MouseEvent) => {
        e.stopPropagation()
        const newMuted = !isMuted
        setIsMuted(newMuted)
        onMuteChange?.(newMuted)
      },
      [isMuted, onMuteChange]
    )

    // Cycle PIP size
    const cyclePipSize = React.useCallback((e: React.MouseEvent) => {
      e.stopPropagation()
      setPipSize((prev) => {
        if (prev === "normal") return "double"
        if (prev === "double") return "fullscreen"
        return "normal"
      })
    }, [])

    // Close PIP
    const closePip = React.useCallback((e: React.MouseEvent) => {
      e.stopPropagation()
      setShowPip(false)
    }, [])

    // Request fullscreen for hero video
    const requestFullscreen = React.useCallback((e: React.MouseEvent) => {
      e.stopPropagation()
      if (!containerRef.current) return
      if (document.fullscreenElement) {
        document.exitFullscreen()
      } else {
        containerRef.current.requestFullscreen()
      }
    }, [])

    return (
      <>
        {/* Hero Video Container */}
        <div
          ref={containerRef}
          className={cn(
            youtubePipPlayerVariants({ size }),
            "group transition-all duration-500",
            className
          )}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          {...props}
        >
          {/* TV Effects - Glow */}
          {enableTvEffects && (
            <>
              <div className="absolute -inset-24 bg-gradient-radial from-white/40 via-white/20 to-transparent blur-[100px] opacity-80 pointer-events-none" />
              <div className="absolute -inset-12 bg-gradient-radial from-white/30 via-white/15 to-transparent blur-[60px] opacity-70 pointer-events-none" />
              <div className="absolute -inset-2 rounded-[30px] bg-gradient-to-r from-white/80 via-white/60 to-white/80 opacity-100 blur-2xl animate-pulse pointer-events-none" />
              <div className="absolute inset-0 rounded-[30px] border-2 border-white/30 shadow-[0_0_60px_rgba(255,255,255,0.5)] pointer-events-none" />
            </>
          )}

          {/* Inner frame glass effect */}
          <div className="absolute inset-0 pointer-events-none z-10">
            <div
              className="absolute inset-0 rounded-[30px] border-2 border-white/10 bg-gradient-to-b from-white/5 to-transparent"
              style={{
                boxShadow:
                  "inset 0 2px 20px rgba(255,255,255,0.1), inset 0 -2px 20px rgba(0,0,0,0.5)",
              }}
            />
          </div>

          {/* Cinematic Vignette */}
          {enableTvEffects && (
            <div
              className="absolute inset-0 z-20 pointer-events-none"
              style={{ boxShadow: "inset 0 0 120px 60px rgba(0,0,0,0.8)" }}
            />
          )}

          {/* Static Effect */}
          {showStatic && enableTvEffects && (
            <div className="absolute inset-0 z-40 pointer-events-none">
              <div className="h-full w-full bg-white/3 animate-pulse" />
              <div
                className="absolute inset-0 opacity-20"
                style={{
                  backgroundImage: `url("data:image/svg+xml,%3Csvg width='200' height='200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' /%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.4'/%3E%3C/svg%3E")`,
                }}
              />
            </div>
          )}

          {/* YouTube Video */}
          <iframe
            className="absolute inset-0 w-full h-full"
            src={getYouTubeEmbedUrl()}
            title="Video"
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />

          {/* Film Grain */}
          {enableTvEffects && (
            <div className="absolute inset-0 pointer-events-none opacity-[0.02] z-10">
              <div
                className="h-full w-full"
                style={{
                  backgroundImage:
                    "repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255,255,255,0.05) 2px, rgba(255,255,255,0.05) 4px)",
                }}
              />
            </div>
          )}

          {/* Controls - Fade in on hover */}
          <div
            className={cn(
              "absolute bottom-6 left-6 flex items-center gap-3 z-30 transition-opacity duration-300",
              isHovered ? "opacity-100" : "opacity-0"
            )}
          >
            <button
              onClick={toggleMute}
              className="flex items-center gap-2 bg-black/80 backdrop-blur-md px-4 py-2 rounded-full hover:bg-black transition-all duration-300 border border-white/10"
            >
              {isMuted ? (
                <VolumeX className="h-4 w-4 text-white" />
              ) : (
                <Volume2 className="h-4 w-4 text-white" />
              )}
              <span className="text-xs text-white/90 font-medium tracking-wider uppercase">
                {isMuted ? "Unmute" : "Mute"}
              </span>
            </button>

            <button
              onClick={requestFullscreen}
              className="flex items-center gap-2 bg-black/80 backdrop-blur-md px-4 py-2 rounded-full hover:bg-black transition-all duration-300 border border-white/10"
            >
              <Maximize className="h-4 w-4 text-white" />
              <span className="text-xs text-white/90 font-medium tracking-wider uppercase">
                Fullscreen
              </span>
            </button>
          </div>

          {/* Live Indicator */}
          {showLiveIndicator && (
            <div className="absolute top-6 left-6 flex items-center gap-2 bg-black/80 backdrop-blur-md px-4 py-2 rounded-full border border-white/10 z-30">
              <div className="w-2 h-2 bg-red-600 rounded-full animate-pulse shadow-[0_0_10px_rgba(220,38,38,0.8)]" />
              <span className="text-xs text-white/90 font-medium tracking-widest uppercase">
                Live
              </span>
            </div>
          )}
        </div>

        {/* PIP Window */}
        {enablePip && isPip && showPip && !isMobile && (
          <div
            ref={pipContainerRef}
            className={cn(
              "fixed z-50 transition-all ease-out group",
              pipSize === "fullscreen"
                ? "inset-0 bg-black/98 backdrop-blur-xl duration-500"
                : isDragging
                  ? "duration-75"
                  : "duration-300",
              isDragging
                ? "cursor-grabbing scale-105 shadow-2xl"
                : pipSize === "fullscreen"
                  ? ""
                  : "cursor-grab hover:scale-105"
            )}
            style={
              pipSize !== "fullscreen"
                ? {
                    left: `${pipPos.x}px`,
                    top: `${pipPos.y}px`,
                    filter: isDragging
                      ? "brightness(1.1) drop-shadow(0 20px 40px rgba(0,0,0,0.5))"
                      : "brightness(1)",
                  }
                : {}
            }
            onMouseDown={handleMouseDown}
            onMouseEnter={() => setIsPipHovered(true)}
            onMouseLeave={() => setIsPipHovered(false)}
          >
            <div
              className={cn(
                "relative bg-black overflow-hidden transition-all duration-500",
                pipSize === "fullscreen"
                  ? "w-full h-full"
                  : pipSize === "double"
                    ? "aspect-video rounded-2xl"
                    : "w-96 aspect-video rounded-2xl"
              )}
              style={pipSize === "double" ? { width: "768px" } : {}}
            >
              {/* PIP TV Effects */}
              {enableTvEffects && pipSize !== "fullscreen" && (
                <>
                  <div className="absolute -inset-12 rounded-full bg-gradient-radial from-white/30 via-white/10 to-transparent blur-3xl opacity-60 pointer-events-none" />
                  <div className="absolute -inset-1 rounded-2xl bg-gradient-to-r from-white/40 via-white/20 to-white/40 opacity-75 blur-xl animate-pulse pointer-events-none" />
                  <div className="absolute inset-0 pointer-events-none z-10">
                    <div
                      className="absolute inset-0 rounded-2xl border-2 border-white/10 bg-gradient-to-b from-white/5 to-transparent"
                      style={{
                        boxShadow:
                          "inset 0 2px 20px rgba(255,255,255,0.1), inset 0 -2px 20px rgba(0,0,0,0.5)",
                      }}
                    />
                  </div>
                  <div className="absolute inset-0 pointer-events-none z-10 opacity-10">
                    <div
                      className="h-full w-full animate-scan"
                      style={{
                        backgroundImage:
                          "repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255,255,255,0.03) 2px, rgba(255,255,255,0.03) 4px)",
                      }}
                    />
                  </div>
                </>
              )}

              {/* PIP YouTube Video */}
              <div className="absolute inset-0 overflow-hidden">
                <iframe
                  className={cn(
                    "absolute top-0 left-0 w-full h-full object-cover",
                    pipSize !== "fullscreen" && "rounded-2xl"
                  )}
                  style={{ aspectRatio: "16 / 9", pointerEvents: "none" }}
                  src={getYouTubeEmbedUrl(true)}
                  title="Video PiP"
                  frameBorder="0"
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                  allowFullScreen
                />
                <div className="absolute inset-0 z-5" />
              </div>

              {/* PIP Controls */}
              <div
                className={cn(
                  "absolute flex items-center gap-2 z-30 transition-opacity duration-300",
                  pipSize === "fullscreen"
                    ? "bottom-10 right-10"
                    : "bottom-3 right-3",
                  isPipHovered ? "opacity-100" : "opacity-0"
                )}
              >
                <button
                  onClick={toggleMute}
                  className="relative p-2.5 bg-black/90 backdrop-blur-md rounded-full hover:bg-black transition-all duration-300 shadow-lg hover:scale-110 border border-white/10"
                  title={isMuted ? "Unmute" : "Mute"}
                >
                  {isMuted ? (
                    <VolumeX className="h-4 w-4 text-white" />
                  ) : (
                    <Volume2 className="h-4 w-4 text-white" />
                  )}
                </button>

                <button
                  onClick={cyclePipSize}
                  className="relative p-2.5 bg-black/90 backdrop-blur-md rounded-full hover:bg-black transition-all duration-300 shadow-lg hover:scale-110 border border-white/10"
                  title={
                    pipSize === "fullscreen"
                      ? "Normal Size"
                      : pipSize === "double"
                        ? "Fullscreen"
                        : "Double Size"
                  }
                >
                  {pipSize === "fullscreen" ? (
                    <Minimize2 className="h-4 w-4 text-white" />
                  ) : (
                    <Maximize2 className="h-4 w-4 text-white" />
                  )}
                </button>

                <button
                  onClick={closePip}
                  className="relative p-2.5 bg-black/90 backdrop-blur-md rounded-full hover:bg-red-600 transition-all duration-300 shadow-lg hover:scale-110 border border-white/10"
                  title="Close"
                >
                  <X className="h-4 w-4 text-white" />
                </button>
              </div>

              {/* PIP Live Indicator */}
              {showLiveIndicator && pipSize !== "fullscreen" && (
                <div className="absolute top-3 right-3 z-20">
                  <div className="flex items-center gap-2 bg-black/80 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10">
                    <div className="w-2 h-2 bg-red-600 rounded-full animate-pulse shadow-[0_0_10px_rgba(220,38,38,0.8)]" />
                    <span className="text-[10px] text-white/80 font-medium tracking-widest uppercase">
                      Live
                    </span>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </>
    )
  }
)

YouTubePipPlayer.displayName = "YouTubePipPlayer"

export { YouTubePipPlayer, youtubePipPlayerVariants }
